!function(){"use strict";
var CFG = {
  // Feed
  m: 100,              // max feed results
  retry: 2,            // jumlah retry fetch
  retryDelay: 1000,    // delay retry pertama (ms), x2 tiap retry

  // Scoring
  t: .45,              // min similarity threshold (45%)
  w: 3,                // min keyword matches

  // Limits
  l: 5,                // max links per artikel
  p: 10,               // min phrase length (karakter)
  maxLinkWords: 5,     // max kata per anchor text
  maxPerParagraph: 2,  // max link per <p>
  earlyParCount: 2,    // jumlah paragraf "awal"
  earlyParMax: 2,      // max total link di paragraf awal

  // Behavior
  o: true,             // satu link per target artikel
  s: ".post .content", // CSS selector konten
  c: "auto-internal-link", // class pada <a>

  // Cache
  cacheTTL: 3600000,   // 1 jam
  cacheKey: "ail_feed_cache",

  // Stop words
  x: "yang dan di dari ke pada untuk dengan ini itu adalah atau sebagai juga sudah akan bisa ada tidak oleh karena dalam saat setelah sebelum namun tetapi jika maka agar supaya saja hanya lebih sangat terlalu belum pernah sering kadang mungkin mestinya seharusnya cara tips tutorial panduan bagaimana apa siapa kapan dimana mengapa kenapa the a an is are was were be been being have has had do does did will would could should may might must shall can need dare ought used to of in on at by about into through during before after above below between under again further then once here there when where why how all any both each few more most other some such no nor not only own same so than too very just now".split(" ")
};

// Util: Ekstrak keyword
function extractKeywords(str) {
  return str.toLowerCase()
    .replace(/[^a-z0-9\s]/g, " ")
    .split(/\s+/)
    .filter(function(w) { return w.length > 2 && CFG.x.indexOf(w) === -1; });
}

// Cache localStorage
function getCache() {
  try {
    var raw = localStorage.getItem(CFG.cacheKey);
    if (!raw) return null;
    var obj = JSON.parse(raw);
    if (Date.now() - obj.ts > CFG.cacheTTL) {
      localStorage.removeItem(CFG.cacheKey);
      return null;
    }
    return obj.data;
  } catch (err) { return null; }
}

function setCache(data) {
  try {
    localStorage.setItem(CFG.cacheKey, JSON.stringify({ ts: Date.now(), data: data }));
  } catch (err) { /* localStorage penuh */ }
}

// Cache invalidasi manual
window.ailClearCache = function() {
  try { localStorage.removeItem(CFG.cacheKey); } catch(e) {}
  console.log("AIL: cache cleared");
};

// Fetch dengan retry + exponential backoff
function fetchFeed(retries, delay) {
  return fetch(window.location.origin + "/feeds/posts/summary?alt=json&max-results=" + CFG.m)
    .then(function(res) {
      if (!res.ok) throw new Error("HTTP " + res.status);
      return res.json();
    })
    .catch(function(err) {
      if (retries > 0) {
        return new Promise(function(resolve, reject) {
          setTimeout(function() {
            fetchFeed(retries - 1, delay * 2).then(resolve).catch(reject);
          }, delay);
        });
      }
      throw err;
    });
}

// Fungsi utama
function init() {
  var contentEl = document.querySelector(CFG.s);
  if (!contentEl) return;

  // Override config via data-attribute
  var ds = contentEl.dataset || {};
  if (ds.ailMax)       CFG.l            = parseInt(ds.ailMax, 10);
  if (ds.ailThreshold) CFG.t            = parseFloat(ds.ailThreshold);
  if (ds.ailMaxWords)  CFG.maxLinkWords = parseInt(ds.ailMaxWords, 10);
  if (ds.ailMaxPara)   CFG.maxPerParagraph = parseInt(ds.ailMaxPara, 10);

  // Visual feedback loading
  contentEl.classList.add("ail-loading");

  var currentUrl = window.location.href.split(/[?#]/)[0];
  var cached = getCache();

  if (cached) {
    processEntries(cached, contentEl, currentUrl);
  } else {
    fetchFeed(CFG.retry, CFG.retryDelay)
      .then(function(r) {
        var entries = r.feed.entry || [];
        setCache(entries);
        processEntries(entries, contentEl, currentUrl);
      })
      .catch(function(err) {
        console.error("AIL error:", err);
        contentEl.classList.remove("ail-loading");

        // Fallback: pakai related/popular posts yang sudah ada
        var fallbackLinks = contentEl.querySelectorAll
          ? null
          : null;
        var sidebar = document.querySelectorAll(".related-posts a[href], .popular-posts a[href]");
        if (sidebar && sidebar.length > 0) {
          var fallbackEntries = [];
          for (var fi = 0; fi < sidebar.length; fi++) {
            var fa = sidebar[fi];
            var ft = (fa.textContent || fa.innerText || "").trim();
            var fu = fa.href.split(/[?#]/)[0];
            if (ft.length > 5 && fu && fu !== currentUrl) {
              fallbackEntries.push({ title: { $t: ft }, link: [{ rel: "alternate", href: fu }] });
            }
          }
          if (fallbackEntries.length > 0) {
            console.log("AIL: using fallback from sidebar (" + fallbackEntries.length + " items)");
            processEntries(fallbackEntries, contentEl, currentUrl);
            return;
          }
        }
        console.warn("AIL: no fallback available");
      });
  }
}

function processEntries(entries, contentEl, currentUrl) {

  // WeakMap → data-attribute (browser compat)
  // Tandai setiap <p> dengan index via data-attribute, bukan WeakMap
  var allParas = contentEl.querySelectorAll("p");
  for (var pi = 0; pi < allParas.length; pi++) {
    allParas[pi].setAttribute("data-ail-idx", pi);
  }

  // Blacklist URL dari <a> yang sudah ada
  var existingLinkUrls = {};
  var existingAnchors = contentEl.querySelectorAll("a[href]");
  for (var ei = 0; ei < existingAnchors.length; ei++) {
    var href = existingAnchors[ei].getAttribute("href").split(/[?#]/)[0].replace(/\/$/, "");
    if (href) existingLinkUrls[href] = true;
  }

  // Parse entries feed
  var articleList = [];
  entries.forEach(function(entry) {
    try {
      var title = entry.title.$t.trim();
      var url = "";
      var links = entry.link || [];
      for (var i = 0; i < links.length; i++) {
        if (links[i].rel === "alternate") {
          url = links[i].href.split(/[?#]/)[0];
          break;
        }
      }
      var urlClean = url.replace(/\/$/, "");
      if (url && url !== currentUrl && title.length > 5 && !existingLinkUrls[urlClean]) {
        articleList.push({ t: title, u: url, k: extractKeywords(title) });
      }
    } catch (err) { /* entry rusak, skip */ }
  });

  if (articleList.length === 0) {
    finalize(contentEl, 0);
    return;
  }

  // TreeWalker — aman dari DOM invalidation
  // TreeWalker di-create sekali dan hanya melangkah saat kita minta,
  // sehingga tidak terpengaruh perubahan DOM setelahnya.
  function buildTextNodeList(root) {
    var list = [];
    var walker = document.createTreeWalker(
      root,
      4, // NodeFilter.SHOW_TEXT
      {
        acceptNode: function(node) {
          var tag = node.parentNode ? node.parentNode.tagName : "";
          if (tag === "A" || tag === "SCRIPT" || tag === "STYLE" || tag === "NOSCRIPT") return 2; // FILTER_REJECT
          if (/^H[1-6]$/.test(tag)) return 2;
          if (node.parentNode && node.parentNode.closest && node.parentNode.closest("a")) return 2;
          if (!node.nodeValue || !node.nodeValue.trim()) return 2;
          return 1; // FILTER_ACCEPT
        }
      },
      false
    );
    var nd;
    while ((nd = walker.nextNode())) {
      // Ambil index paragraf dari data-ail-idx ancestor <p>
      var paraEl = nd.parentNode ? nd.parentNode.closest("p") : null;
      var paraIdx = paraEl ? parseInt(paraEl.getAttribute("data-ail-idx"), 10) : -1;
      list.push({ node: nd, paraEl: paraEl, paraIdx: isNaN(paraIdx) ? -1 : paraIdx });
    }
    return list;
  }

  var textNodes = buildTextNodeList(contentEl);
  var fullText = textNodes.map(function(td) { return td.node.nodeValue; }).join(" ");
  var contentKeywords = extractKeywords(fullText);
  var contentLower = fullText.toLowerCase();

  // Scoring
  var scored = [];
  articleList.forEach(function(art) {
    var matches = 0;
    art.k.forEach(function(kw) {
      if (contentKeywords.indexOf(kw) !== -1) matches++;
    });
    var similarity = art.k.length > 0 ? matches / art.k.length : 0;
    if (similarity >= CFG.t && matches >= CFG.w) {
      scored.push({ a: art, v: similarity, m: matches });
    }
  });

  scored.sort(function(a, b) { return b.v - a.v || b.m - a.m; });

  var candidates = scored.slice(0, CFG.l * 8);
  var linkItems = [];
  var usedTargets = {};

  candidates.forEach(function(item) {
    var titleLower = item.a.t.toLowerCase();
    var keywords = item.a.k;
    var bestMatch = null;

    // STRATEGI 1: Judul lengkap
    var fullTitleClean = titleLower.replace(/[^a-z0-9\s]/g, " ").replace(/\s+/g, " ").trim();
    var fullTitleWords = fullTitleClean.split(" ").filter(function(w) { return w.length > 2; });
    var fullTitlePhrase = fullTitleWords.join(" ");

    if (fullTitlePhrase.length >= CFG.p && fullTitleWords.length >= 2 && fullTitleWords.length <= CFG.maxLinkWords) {
      var pat = new RegExp("(^|[^a-z0-9])(" + fullTitlePhrase.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + ")([^a-z0-9]|$)", "i");
      if (pat.test(contentLower)) {
        bestMatch = { ph: fullTitlePhrase, re: pat, exact: true, wordCount: fullTitleWords.length, priority: 100 };
      }
    }

    // STRATEGI 2: Frase terpanjang valid
    if (!bestMatch) {
      var maxW = Math.min(keywords.length, CFG.maxLinkWords);
      outer:
      for (var wc = maxW; wc >= 2; wc--) {
        for (var i = 0; i <= keywords.length - wc; i++) {
          var phrase = keywords.slice(i, i + wc).join(" ");
          if (phrase.length >= CFG.p) {
            var pp = new RegExp("(^|[^a-z0-9])(" + phrase.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + ")([^a-z0-9]|$)", "i");
            if (pp.test(contentLower)) {
              var isExact = titleLower.indexOf(phrase) !== -1;
              var prio = isExact ? 50 : wc;
              if (!bestMatch || prio > bestMatch.priority || (prio === bestMatch.priority && phrase.length > bestMatch.ph.length)) {
                bestMatch = { ph: phrase, re: pp, exact: isExact, wordCount: wc, priority: prio };
              }
            }
          }
        }
        if (bestMatch && bestMatch.wordCount >= 4 && bestMatch.exact) break outer;
      }
    }

    if (bestMatch) {
      var key = item.a.u;
      if (!CFG.o || !usedTargets[key]) {
        linkItems.push({
          re: bestMatch.re, u: item.a.u, ti: item.a.t, ky: key,
          ph: bestMatch.ph, exact: bestMatch.exact,
          wordCount: bestMatch.wordCount, priority: bestMatch.priority
        });
        usedTargets[key] = true;
      }
    }
  });

  linkItems.sort(function(a, b) {
    if (b.priority !== a.priority) return b.priority - a.priority;
    if (b.wordCount !== a.wordCount) return b.wordCount - a.wordCount;
    if (b.exact !== a.exact) return (b.exact ? 1 : 0) - (a.exact ? 1 : 0);
    return b.ti.length - a.ti.length;
  });

  // Dedup frase tumpang tindih
  var usedPhrases = {};
  linkItems = linkItems.filter(function(item) {
    if (usedPhrases[item.ph]) return false;
    usedPhrases[item.ph] = true;
    return true;
  });

  // Session dedup frase (lintas text node)
  var sessionLinkedPhrases = {};

  // Terapkan link: DOM order maju, distribusi merata
  var totalLinks = 0;
  var linkedTargets = {};
  var linkCountPerPara = {};
  var earlyParLinks = 0;

  for (var m = 0; m < textNodes.length; m++) {
    if (totalLinks >= CFG.l) break;

    var td = textNodes[m];
    // Setelah replace, node lama sudah di-remove — cek apakah masih di DOM
    if (!td.node.parentNode) continue;

    var nodeVal = td.node.nodeValue;
    if (!nodeVal || !nodeVal.trim()) continue;

    var paraIdx = td.paraIdx;
    var countInThisPara = (paraIdx >= 0 && linkCountPerPara[paraIdx]) ? linkCountPerPara[paraIdx] : 0;
    var isEarlyPar = (paraIdx >= 0 && paraIdx < CFG.earlyParCount);

    if (isEarlyPar && earlyParLinks >= CFG.earlyParMax) continue;
    if (paraIdx >= 0 && countInThisPara >= CFG.maxPerParagraph) continue;

    for (var r = 0; r < linkItems.length; r++) {
      var lnk = linkItems[r];
      if (CFG.o && linkedTargets[lnk.ky]) continue;
      if (sessionLinkedPhrases[lnk.ph]) continue; // [FITUR 18]
      if (!lnk.re.test(nodeVal)) continue;

      var inserted = false;
      var newHtml = nodeVal.replace(lnk.re, function(match, before, phrase, after) {
        if (totalLinks >= CFG.l || inserted) return match;
        if (CFG.o && linkedTargets[lnk.ky]) return match;
        if (sessionLinkedPhrases[lnk.ph]) return match; // [FITUR 18]

        totalLinks++;
        linkedTargets[lnk.ky] = true;
        sessionLinkedPhrases[lnk.ph] = true;
        inserted = true;

        // Analytics tracking
        var analyticsAttr = 'onclick="try{if(window.gtag)gtag(\'event\',\'click\',{event_category:\'AIL\',event_label:this.href});else if(window.ga)ga(\'send\',\'event\',\'AIL\',\'click\',this.href);}catch(e){}"';

        return before +
          '<a href="' + lnk.u + '" ' +
          'class="' + CFG.c + '" ' +
          'data-ail-target="' + lnk.ky + '" ' +
          'title="' + lnk.ti.replace(/"/g, "&quot;") + '" ' +
          'rel="noopener" ' +
          analyticsAttr + '>' +
          phrase + '</a>' + after;
      });

      if (newHtml !== nodeVal) {
        if (paraIdx >= 0) {
          linkCountPerPara[paraIdx] = countInThisPara + 1;
          if (isEarlyPar) earlyParLinks++;
        }

        var span = document.createElement("span");
        span.innerHTML = newHtml;
        var parent = td.node.parentNode;
        if (parent) {
          while (span.firstChild) parent.insertBefore(span.firstChild, td.node);
          parent.removeChild(td.node);
        }
        break;
      }
    }
  }

  // Cleanup data-ail-idx dari DOM
  for (var ci = 0; ci < allParas.length; ci++) {
    allParas[ci].removeAttribute("data-ail-idx");
  }

  finalize(contentEl, totalLinks);
}

// Visual feedback selesai
function finalize(contentEl, count) {
  contentEl.classList.remove("ail-loading");
  contentEl.classList.add("ail-done");
  console.log("AIL v3.0: " + count + " links created");
}

// IntersectionObserver
var observer = new IntersectionObserver(function(entries) {
  entries.forEach(function(entry) {
    if (entry.isIntersecting) {
      if ("requestIdleCallback" in window) {
        requestIdleCallback(init, { timeout: 2000 });
      } else {
        setTimeout(init, 1500);
      }
      observer.disconnect();
    }
  });
}, { rootMargin: "200px 0px" });

var target = document.querySelector(CFG.s);
if (target) observer.observe(target);

}();

/*
=== CSS OPSIONAL (tambahkan ke template Blogger) ===

.ail-loading { opacity: 0.85; }
.ail-done    { opacity: 1; transition: opacity 0.3s ease; }

a.auto-internal-link {
  border-bottom: 1px dotted currentColor;
  text-decoration: none;
}
a.auto-internal-link:hover {
  border-bottom-style: solid;
}

=== CARA PAKAI data-attribute ===

<div class="post-content" data-ail-max="7" data-ail-threshold="0.4" data-ail-max-words="4" data-ail-max-para="2">
  ...isi artikel...
</div>

=== CACHE MANUAL ===

Ketik di console browser: ailClearCache()
Atau tambahkan tombol di admin: <button onclick="ailClearCache()">Clear AIL Cache</button>
*/
